-- Ken's Hardened V2 Fix

local b64_0xlIIIII = {}
local char_0x1I1lII='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIIlIIl=1,#char_0x1I1lII do b64_0xlIIIII[char_0x1I1lII:sub(i_0xIIlIIl,i_0xIIlIIl)] = i_0xIIlIIl - 1 end

function b64_0xlIIIII.dec_0xlIIIlI(d_0xIlIlIl)
    d_0xIlIlIl = string.gsub(d_0xIlIlIl, '[^'..char_0x1I1lII..'=]', '')
    local r_0xIllIII = {}
    for i_0xIIlIIl=1, #d_0xIlIlIl, 4 do
        local c_0x1IllIl = b64_0xlIIIII[d_0xIlIlIl:sub(i_0xIIlIIl,i_0xIIlIIl)] or 0
        local c_0xl1llI1 = b64_0xlIIIII[d_0xIlIlIl:sub(i_0xIIlIIl+1,i_0xIIlIIl+1)] or 0
        local c_0xI1llll, c_0xlI1IlI = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIlIlIl:sub(i_0xIIlIIl+2,i_0xIIlIIl+2)
        if ch3 == "=" then has3 = false else c_0xI1llll = b64_0xlIIIII[ch3] or 0 end
        local ch4 = d_0xIlIlIl:sub(i_0xIIlIIl+3,i_0xIIlIIl+3)
        if ch4 == "=" then has4 = false else c_0xlI1IlI = b64_0xlIIIII[ch4] or 0 end
        local b_0xllllI1 = c_0x1IllIl * (2^18) + c_0xl1llI1 * (2^12) + c_0xI1llll * (2^6) + c_0xlI1IlI
        local b_0xIl1IIl = math.floor(b_0xllllI1 / (2^16)) % (2^8)
        local b_0xllllII = math.floor(b_0xllllI1 / (2^8)) % (2^8)
        local b_0xll1lIl = b_0xllllI1 % (2^8)
        table.insert(r_0xIllIII, string.char(b_0xIl1IIl))
        if has3 then table.insert(r_0xIllIII, string.char(b_0xllllII)) end
        if has4 then table.insert(r_0xIllIII, string.char(b_0xll1lIl)) end
    end
    return table.concat(r_0xIllIII)
end


local function bxor_0xIIlI1I(a_0xIllIl1,b_0xlIII1l)
    if bit32 then return bit32.bxor(a_0xIllIl1,b_0xlIII1l) end
    local r_0xll1IlI = 0
    for i_0xl1l1Il = 0, 7 do
        local x_0xIIIlll = a_0xIllIl1 % 2
        local y_0xllllI1 = b_0xlIII1l % 2
        if x_0xIIIlll ~= y_0xllllI1 then r_0xll1IlI = r_0xll1IlI + (2^i_0xl1l1Il) end
        a_0xIllIl1 = math.floor(a_0xIllIl1 / 2)
        b_0xlIII1l = math.floor(b_0xlIII1l / 2)
    end
    return r_0xll1IlI
end


local function bxor_str_0xl1IIll(s_0xl1lIll, k_0xII1lIl)
    local r_0xIIIlIl = {}
    for i_0xll1I1l=1, #s_0xl1lIll do
        local b_0xIII1II = string.byte(s_0xl1lIll, i_0xll1I1l)
        local kb_0xlIIIlI = string.byte(k_0xII1lIl, (i_0xll1I1l-1) % #k_0xII1lIl + 1)
        r_0xIIIlIl[i_0xll1I1l] = string.char(bxor_0xIIlI1I(b_0xIII1II, kb_0xlIIIlI))
    end
    return table.concat(r_0xIIIlIl)
end


local function getkeys_0x11llIl()
    local seed = b64_0xlIIIII.dec_0xlIIIlI("Wld2bHN0bVA=")
    local k1_enc = b64_0xlIIIII.dec_0xlIIIlI("M2YSXkZGBmU=")
    local k2_enc = b64_0xlIIIII.dec_0xlIIIlI("HQ4gKiM7G2c=")
    return bxor_str_0xl1IIll(k1_enc, seed), bxor_str_0xl1IIll(k2_enc, seed)
end


local function cff_0xlI1llI(a_0xllllll)
    local st_0xl1III1 = 0
    local res_0xlIlIlI = a_0xllllll
    while true do
        if st_0xl1III1 == 0 then
            res_0xlIlIlI = res_0xlIlIlI + 1
            st_0xl1III1 = 1
        elseif st_0xl1III1 == 1 then
            res_0xlIlIlI = res_0xlIlIlI * 2
            st_0xl1III1 = 2
        elseif st_0xl1III1 == 2 then
            res_0xlIlIlI = res_0xlIlIlI - 3
            st_0xl1III1 = 3
        else
            break
        end
    end
    return res_0xlIlIlI
end


local function chain_0x1IlIlI(x) return x*2 end
local function chain_0xlIllll(x) return chain_0x1IlIlI(x)+1 end


local d_0x1lIlll = {
  {op=255, val="", is_enc=true},
}
local pc_0xII1ll1 = 1
local stk_0xII1II1 = {}
stk_0xII1II1._jmp = nil


local disp_0xl1lI1l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0x11llIl()

local state_0xIIl1I1 = 0
while true do
    if state_0xIIl1I1 == 0 then  -- FETCH
        if pc_0xII1ll1 > #d_0x1lIlll then break end
        local inst = d_0x1lIlll[pc_0xII1ll1]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlIIIII.dec_0xlIIIlI(val)
            d = bxor_str_0xl1IIll(d, k2)
            val = bxor_str_0xl1IIll(d, k1)
        end
        stk_0xII1II1._jmp = nil
        pc_0xII1ll1 = pc_0xII1ll1 + 1
        cur_op_0x1IlII1 = opcode
        cur_val_0x1lI1lI = val
        state_0xIIl1I1 = 1

    elseif state_0xIIl1I1 == 1 then  -- EXECUTE
        local handler = disp_0xl1lI1l[cur_op_0x1IlII1]
        if handler then
            handler(stk_0xII1II1, cur_val_0x1lI1lI)
        end
        if stk_0xII1II1._jmp then
            pc_0xII1ll1 = pc_0xII1ll1 + stk_0xII1II1._jmp
        end
        state_0xIIl1I1 = 0
    else
        break
    end
end
